import { FastifyRequest, FastifyReply } from 'fastify';
import Redis from 'ioredis';
import { config } from '../config';

const redis = new Redis({
  host: config.redis.host,
  port: config.redis.port,
  password: config.redis.password || undefined,
  db: config.redis.db || 0,
});

interface RateLimitResult {
  allowed: boolean;
  limit: number;
  remaining: number;
  resetAt: Date;
}

async function checkRateLimit(apiKeyId: string, limit: number, windowMs: number = 60000): Promise<RateLimitResult> {
  const now = Date.now();
  const windowStart = now - windowMs;
  const key = `ratelimit:${apiKeyId}`;

  // Sliding window using sorted set
  const pipeline = redis.pipeline();
  pipeline.zremrangebyscore(key, 0, windowStart); // Remove expired entries
  pipeline.zadd(key, now.toString(), `${now}:${Math.random()}`); // Add current request
  pipeline.zcard(key); // Count requests in window
  pipeline.pexpire(key, windowMs); // Set TTL

  const results = await pipeline.exec();
  const count = (results?.[2]?.[1] as number) || 0;

  return {
    allowed: count <= limit,
    limit,
    remaining: Math.max(0, limit - count),
    resetAt: new Date(now + windowMs),
  };
}

export async function apiRateLimitHook(req: FastifyRequest, reply: FastifyReply): Promise<void> {
  const apiKey = (req as any).apiKey;
  if (!apiKey) return;

  const limit = apiKey.rate_limit || 1000; // per minute
  const result = await checkRateLimit(apiKey.id, limit, 60000);

  reply.header('X-RateLimit-Limit', result.limit);
  reply.header('X-RateLimit-Remaining', result.remaining);
  reply.header('X-RateLimit-Reset', result.resetAt.toISOString());

  if (!result.allowed) {
    reply.status(429).send({
      success: false,
      error: {
        code: 'RATE_LIMIT_EXCEEDED',
        message: `Rate limit of ${result.limit} requests per minute exceeded`,
        retry_after: Math.ceil((result.resetAt.getTime() - Date.now()) / 1000),
      },
    });
    return;
  }
}

