import { URL } from 'url';
import dns from 'dns/promises';
import net from 'net';

// Private/reserved IP ranges that should never be accessed
const BLOCKED_IP_RANGES = [
  // IPv4 private ranges
  { start: '10.0.0.0', end: '10.255.255.255' },
  { start: '172.16.0.0', end: '172.31.255.255' },
  { start: '192.168.0.0', end: '192.168.255.255' },
  // Loopback
  { start: '127.0.0.0', end: '127.255.255.255' },
  // Link-local
  { start: '169.254.0.0', end: '169.254.255.255' },
  // AWS/cloud metadata
  { start: '169.254.169.254', end: '169.254.169.254' },
  // Localhost IPv4
  { start: '0.0.0.0', end: '0.255.255.255' },
];

const BLOCKED_HOSTNAMES = [
  'localhost',
  'metadata.google.internal',
  'metadata.google.com',
  '169.254.169.254',
];

function ipToLong(ip: string): number {
  return ip.split('.').reduce((acc, octet) => (acc << 8) + parseInt(octet), 0) >>> 0;
}

function isPrivateIP(ip: string): boolean {
  if (net.isIPv6(ip)) return ip === '::1' || ip.startsWith('fe80:') || ip.startsWith('fc') || ip.startsWith('fd');
  const ipLong = ipToLong(ip);
  return BLOCKED_IP_RANGES.some(range => {
    const start = ipToLong(range.start);
    const end = ipToLong(range.end);
    return ipLong >= start && ipLong <= end;
  });
}

export async function validateMediaUrl(urlString: string): Promise<{ valid: boolean; error?: string }> {
  // 1. Parse URL
  let parsed: URL;
  try {
    parsed = new URL(urlString);
  } catch {
    return { valid: false, error: 'Invalid URL format' };
  }

  // 2. Only allow http and https
  if (!['http:', 'https:'].includes(parsed.protocol)) {
    return { valid: false, error: `Protocol '${parsed.protocol}' not allowed. Only http and https are supported.` };
  }

  // 3. Block known internal hostnames
  const hostname = parsed.hostname.toLowerCase();
  if (BLOCKED_HOSTNAMES.includes(hostname)) {
    return { valid: false, error: `Hostname '${hostname}' is not allowed` };
  }

  // 4. Resolve DNS and check if IP is private (prevents DNS rebinding)
  try {
    const addresses = await dns.resolve4(hostname).catch(() => []);
    const addresses6 = await dns.resolve6(hostname).catch(() => []);
    const allAddresses = [...addresses, ...addresses6];

    if (allAddresses.length === 0) {
      // If hostname is already an IP, check directly
      if (net.isIP(hostname)) {
        if (isPrivateIP(hostname)) {
          return { valid: false, error: 'URLs pointing to private/internal IP addresses are not allowed' };
        }
      }
      // else: DNS didn't resolve, let Baileys handle the error naturally
      return { valid: true };
    }

    for (const addr of allAddresses) {
      if (isPrivateIP(addr)) {
        return { valid: false, error: 'URLs pointing to private/internal IP addresses are not allowed' };
      }
    }
  } catch {
    // DNS resolution failed — URL may still be valid (e.g., CDN with CNAME)
    return { valid: true };
  }

  return { valid: true };
}

